  "@type": "WebSite",
  "name": "My Linux Help",
  "url": "https://my-linux-help.blogspot.com/",
  "description": "Guías de Linux en español: tutoriales, comandos, herramientas y distribuciones para todos los niveles.",
  "inLanguage": "es",
  "potentialAction": {
    "@type": "SearchAction",
