  }
}

head.b:skin:
:root {
  /* PALETA DE COLORES (MODO CLARO) */
  --bg: #f8fafc; 
  --surface: #ffffff;
  --surface2: #f1f5f9; 
  --border: #e2e8f0; 
  --border2: #cbd5e1; 

  --text: #0f172a; 
  --muted: #475569; 
  --subtle: #94a3b8; 

  --accent: #0284c7; 
  --accent-light: #e0f2fe; 
  --accent-mid: #0369a1; 
  --accent-dark: #0f172a; 

  --btn-primary: #38bdf8; 
  --btn-primary-hover: #7dd3fc; 

  /* FUENTES */
  --font-display: 'Montserrat', sans-serif;
  --font-body: 'Montserrat', sans-serif;
  --font-mono: monospace;

  --max: 1200px;
  --r: clamp(6px, 1.5vw, 8px);
  --r-lg: clamp(10px, 2vw, 14px);
}

/* PALETA DE COLORES (MODO OSCURO) */
body.dark-mode {
  --bg: #0f172a;          
  --surface: #1e293b;     
  --surface2: #334155;    
  --border: #334155;      
  --border2: #475569; 

  --text: #f8fafc;        
  --muted: #cbd5e1;       
  --subtle: #64748b;      

  --accent: #38bdf8;      
  --accent-light: #0f263c;
  --accent-mid: #0ea5e9;
  --accent-dark: #ffffff; 
}

*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

html { scroll-behavior: smooth; font-size: 100%; }

body {
  font-family: var(--font-body);
  background: var(--bg);
  color: var(--text);
  line-height: 1.65;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden; 
  width: 100vw;
  transition: background 0.3s ease, color 0.3s ease;
}

a { color: inherit; text-decoration: none; }
img { max-width: 100%; display: block; border-radius: var(--r); }

body.dark-mode .social-link {
  border-color: var(--border);
  color: var(--muted);
}
body.dark-mode .nav-link.active {
  color: #fff;
}
body.dark-mode .slide-overlay {
  background: linear-gradient(90deg, rgba(15, 23, 42, 0.98) 0%, rgba(15, 23, 42, 0.85) 50%, rgba(15, 23, 42, 0.4) 100%);
}

/* ── HEADER ── */
header { background: var(--surface); border-bottom: 1px solid var(--border); position: sticky; top: 0; z-index: 100; width: 100%; transition: background 0.3s, border-color 0.3s; }
.header-top { max-width: var(--max); margin: 0 auto; padding: clamp(0.5rem, 2vw, 1rem) clamp(1rem, 3vw, 1.5rem); display: flex; align-items: center; justify-content: space-between; gap: 1rem; flex-wrap: wrap; }
.logo { display: flex; align-items: center; gap: 10px; font-family: var(--font-display); font-size: clamp(1.2rem, 3vw, 1.4rem); font-weight: 800; color: var(--accent-dark); letter-spacing: -0.5px; }

.header-search { flex: 1; max-width: 360px; min-width: 200px; position: relative; }
.header-search input { width: 100%; background: var(--surface2); border: 1px solid var(--border); border-radius: 100px; padding: 0.5rem 1rem 0.5rem 2.4rem; font-size: clamp(0.8rem, 2vw, 0.87rem); font-family: var(--font-body); color: var(--text); outline: none; transition: border-color .2s, background .2s, color .2s; }
.header-search input:focus { border-color: var(--accent); }
.header-search svg { position: absolute; left: 0.8rem; top: 50%; transform: translateY(-50%); width: 16px; height: 16px; stroke: var(--subtle); stroke-width: 2; fill: none; }
.header-actions { display: flex; align-items: center; gap: clamp(0.4rem, 1.5vw, 0.75rem); }
.btn-suscribirse { background: var(--accent); color: #fff; border: none; border-radius: 100px; padding: clamp(0.4rem, 1.5vw, 0.5rem) clamp(1rem, 2vw, 1.4rem); font-size: clamp(0.75rem, 2vw, 0.85rem); font-weight: 700; font-family: var(--font-body); cursor: pointer; transition: background .2s, transform .1s; }
.btn-suscribirse:hover { background: var(--accent-mid); transform: translateY(-1px); }

#theme-toggle { cursor: pointer; background: transparent; border: none; color: var(--text); }
#theme-toggle svg { width: 18px; height: 18px; fill: none; stroke: currentColor; stroke-width: 2; }

.social-link { width: clamp(32px, 8vw, 36px); height: clamp(32px, 8vw, 36px); border-radius: 50%; border: 1px solid var(--border); display: flex; align-items: center; justify-content: center; color: var(--muted); transition: border-color .2s, color .2s, background .2s; }
.social-link:hover { border-color: var(--accent); color: #fff; background: var(--accent); }
.social-link svg { width: 16px; height: 16px; fill: currentColor; }

/* NAV */
nav { border-top: 1px solid var(--border); background: var(--surface); width: 100%; transition: background 0.3s, border-color 0.3s; }
.nav-inner { max-width: var(--max); margin: 0 auto; padding: 0 clamp(1rem, 3vw, 1.5rem); display: flex; align-items: center; gap: 0; overflow-x: auto; scrollbar-width: none; }
.nav-inner::-webkit-scrollbar { display: none; }
.nav-link { font-size: clamp(0.8rem, 2vw, 0.85rem); font-weight: 600; color: var(--muted); padding: clamp(0.6rem, 2vw, 0.8rem) clamp(0.8rem, 2vw, 1.2rem); border-bottom: 2px solid transparent; white-space: nowrap; transition: color .2s, border-color .2s; }
.nav-link:hover { color: var(--text); }
.nav-link.active { color: var(--accent-dark); border-bottom-color: var(--accent); }

/* ── SLIDER HERO ── */
.hero-slider { position: relative; width: 100%; height: clamp(350px, 60vh, 480px); overflow: hidden; background: #0f172a; border-bottom: 1px solid var(--border); }
.slide { position: absolute; inset: 0; opacity: 0; transition: opacity 0.6s ease-in-out; display: flex; align-items: center; justify-content: center; z-index: 0; }
.slide.active { opacity: 1; z-index: 1; }
.slide-bg { position: absolute; inset: -30px; background-size: cover; background-position: center; filter: blur(15px); opacity: 0.5; z-index: 1; }
.slide-overlay { position: absolute; inset: 0; background: linear-gradient(90deg, rgba(15, 23, 42, 0.95) 0%, rgba(15, 23, 42, 0.75) 50%, rgba(15, 23, 42, 0.3) 100%); z-index: 2; }
.slide-content { position: relative; z-index: 3; max-width: var(--max); width: 100%; margin: 0 auto; padding: 0 clamp(1.5rem, 4vw, 2rem); display: grid; grid-template-columns: 1fr 1fr; gap: clamp(1.5rem, 4vw, 3rem); align-items: center; }
.slide-text h2 { font-family: var(--font-display); font-size: clamp(1.6rem, 5vw, 2.2rem); font-weight: 800; color: #fff; margin-bottom: clamp(0.5rem, 2vw, 1rem); line-height: 1.25; letter-spacing: -0.5px; }
.slide-text p { color: rgba(255,255,255,0.85); font-size: clamp(0.9rem, 2.5vw, 1.05rem); margin-bottom: clamp(1rem, 3vw, 1.8rem); line-height: 1.6; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }
.btn-hero-primary { background: var(--btn-primary); color: #0f172a; border: none; border-radius: var(--r); padding: clamp(0.6rem, 2vw, 0.75rem) clamp(1.2rem, 3vw, 1.8rem); font-size: clamp(0.85rem, 2vw, 0.95rem); font-weight: 700; cursor: pointer; transition: background .2s, transform .2s; display: inline-block; }
.btn-hero-primary:hover { background: var(--btn-primary-hover); transform: translateY(-2px); }
.slide-img-container { position: relative; width: 100%; height: clamp(200px, 40vh, 340px); border-radius: var(--r-lg); overflow: hidden; box-shadow: 0 15px 35px rgba(0,0,0,0.4); }
.slide-img-container img { width: 100%; height: 100%; object-fit: cover; object-position: center; border-radius: 0; }
.slider-dots { position: absolute; bottom: clamp(15px, 4vw, 25px); left: 50%; transform: translateX(-50%); display: flex; gap: 12px; z-index: 10; }
.dot { width: 12px; height: 12px; border-radius: 50%; background: rgba(255,255,255,0.3); cursor: pointer; transition: background 0.3s, transform 0.2s; }
.dot.active { background: var(--btn-primary); transform: scale(1.2); }

/* ── MAIN LAYOUT ── */
.page { max-width: var(--max); width: 100%; margin: 0 auto; padding: clamp(1.5rem, 4vw, 3rem) clamp(1rem, 3vw, 1.5rem); display: grid; grid-template-columns: minmax(0, 1fr) minmax(280px, 340px); gap: clamp(1.5rem, 4vw, 3rem); align-items: start; }

/* ── CATEGORY SECTION ── */
.section-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 1.25rem; padding-bottom: 0.75rem; border-bottom: 2px solid var(--border); transition: border-color 0.3s; }
.section-title { font-size: clamp(1.1rem, 3vw, 1.25rem); font-weight: 800; display: flex; align-items: center; gap: 0.6rem; letter-spacing: -0.5px; }
.section-icon { width: 30px; height: 30px; border-radius: 6px; display: flex; align-items: center; justify-content: center; background: var(--surface2); transition: background 0.3s; }
.section-all { font-size: 0.85rem; font-weight: 600; color: var(--accent); }
.category-block { margin-bottom: clamp(2rem, 5vw, 3.5rem); }

.posts-row { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.25rem; }
.post-card { background: var(--surface); border: 1px solid var(--border); border-radius: var(--r-lg); display: flex; flex-direction: column; cursor: pointer; transition: transform .2s, box-shadow .2s, background .3s, border-color .3s; overflow: hidden; }
.post-card:hover { transform: translateY(-4px); box-shadow: 0 12px 30px rgba(0,0,0,0.08); border-color: var(--accent); }
body.dark-mode .post-card:hover { box-shadow: 0 12px 30px rgba(0,0,0,0.3); }
.post-thumb { aspect-ratio: 16/9; width: 100%; object-fit: cover; object-position: center; border-bottom: 1px solid var(--border); transition: border-color 0.3s; }
.post-body { padding: clamp(1rem, 2vw, 1.25rem); display: flex; flex-direction: column; flex: 1; }
.post-tag { font-size: 0.7rem; font-weight: 700; text-transform: uppercase; padding: 0.25rem 0.75rem; border-radius: 4px; background: var(--accent-light); color: var(--accent); margin-bottom: 0.75rem; align-self: flex-start; transition: background 0.3s, color 0.3s; }
.post-card h3 { font-size: clamp(0.95rem, 2vw, 1.05rem); font-weight: 700; line-height: 1.35; margin-bottom: 0.5rem; }
.post-card p { font-size: 0.85rem; color: var(--muted); margin-bottom: 1rem; transition: color 0.3s; }
.post-meta { display: flex; align-items: center; font-size: 0.78rem; font-weight: 500; color: var(--subtle); border-top: 1px solid var(--border); padding-top: 0.75rem; margin-top: auto; transition: border-color 0.3s; }

/* ── SINGLE POST LECTOR ── */
.reader-mode { background: var(--surface); padding: clamp(1.5rem, 5vw, 45px); border-radius: var(--r-lg); border: 1px solid var(--border); box-shadow: 0 10px 30px rgba(0,0,0,0.03); width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; word-wrap: break-word !important; word-break: break-word !important; transition: background 0.3s, border-color 0.3s; }
.reader-title { font-size: clamp(1.6rem, 5vw, 2.4rem); font-weight: 800; margin-bottom: 15px; letter-spacing: -0.5px; word-break: break-word; }
.reader-meta { display: flex; flex-wrap: wrap; gap: 15px; font-size: clamp(0.85rem, 2vw, 0.95rem); font-weight: 500; color: var(--muted); margin-bottom: 30px; border-bottom: 1px dashed var(--border2); padding-bottom: 15px; transition: color 0.3s, border-color 0.3s; }
.reader-content { font-size: clamp(1rem, 2.5vw, 1.05rem); line-height: 1.8; color: var(--muted); transition: color 0.3s; }
.reader-content > * { max-width: 100%; }
.reader-content a { word-break: break-all; color: var(--accent); }
.reader-content img, .reader-content video { height: auto !important; border-radius: var(--r); margin: 1.5rem 0; object-fit: contain; }
.reader-content iframe, .reader-content embed, .reader-content object { width: 100% !important; aspect-ratio: 16/9; height: auto !important; border-radius: var(--r); }
.reader-content table { display: table; width: 100%; overflow-x: auto; border-collapse: collapse; margin-bottom: 1.5rem; word-break: normal; border: 1px solid var(--border); border-radius: var(--r); }
.reader-content th, .reader-content td { padding: 0.6rem 1rem; border: 1px solid var(--border); text-align: left; font-size: clamp(0.8rem, 2vw, 0.9rem); }
.reader-content th { background: var(--surface2); font-weight: 700; color: var(--text); }
.reader-content tr:nth-child(even) { background: var(--surface2); }
.reader-content h2, .reader-content h3 { font-size: clamp(1.3rem, 4vw, 1.6rem); color: var(--text); margin: 35px 0 15px; font-weight: 700; word-break: break-word; transition: color 0.3s; }

/* BLOQUES DE CÓDIGO Y COMANDOS */
.reader-content pre { background: var(--surface2) !important; color: var(--text) !important; padding: clamp(15px, 3vw, 20px) !important; border-radius: 8px; width: 100% !important; overflow-x: auto !important; white-space: pre !important; word-break: normal !important; font-size: clamp(0.8rem, 2vw, 0.9rem); font-family: var(--font-mono); border: 1px solid var(--border); margin: 1rem 0; }
.reader-content code { background: var(--surface2) !important; color: var(--accent) !important; padding: 0.2em 0.4em !important; border-radius: 4px; font-size: 0.9em; font-family: var(--font-mono); border: 1px solid var(--border); }
.reader-content pre code { background: transparent !important; color: inherit !important; padding: 0 !important; border: none !important; border-radius: 0; }
body.dark-mode .reader-content pre { background: #020617 !important; color: #38bdf8 !important; border-color: #1e293b; }
body.dark-mode .reader-content code { background: #0f172a !important; color: #38bdf8 !important; border-color: #1e293b; }
body.dark-mode .reader-content pre code { background: transparent !important; color: inherit !important; }

/* CONTENEDOR Y BOTÓN COPIAR COMPONENTES */
.code-block-wrapper { position: relative; margin: 1.5rem 0; width: 100%; }
.code-block-wrapper pre { margin: 0 !important; padding-right: 90px !important; }
.btn-copy-code { position: absolute; top: 10px; right: 10px; background: rgba(255, 255, 255, 0.08); border: 1px solid rgba(255, 255, 255, 0.15); border-radius: 6px; color: #cbd5e1; padding: 6px 10px; font-size: 0.75rem; font-family: var(--font-body); font-weight: 700; cursor: pointer; display: flex; align-items: center; gap: 5px; transition: all 0.2s ease; backdrop-filter: blur(4px); -webkit-backdrop-filter: blur(4px); z-index: 10; }
.btn-copy-code:hover { background: var(--accent); border-color: var(--accent); color: #fff; transform: translateY(-1px); }
.btn-copy-code.copied { background: #10b981 !important; border-color: #10b981 !important; color: #fff !important; }

/* ── SIDEBAR ── */
.sidebar { display: flex; flex-direction: column; gap: clamp(1rem, 3vw, 1.5rem); position: sticky; top: 100px; width: 100%; }
.widget { background: var(--surface); border: 1px solid var(--border); border-radius: var(--r-lg); overflow: hidden; width: 100%; transition: background 0.3s, border-color 0.3s; }
.widget-head { padding: 1.25rem 1.25rem 0.85rem; border-bottom: 1px solid var(--border); font-size: 0.85rem; font-weight: 700; color: var(--muted); letter-spacing: 0.05em; text-transform: uppercase; display: flex; align-items: center; gap: 0.6rem; transition: border-color 0.3s, color 0.3s; }
.widget-head svg { width: 16px; height: 16px; stroke: currentColor; fill: none; stroke-width: 2.5; }

/* CONTADORES */
.counter-widget .widget-body { padding: clamp(1rem, 3vw, 1.5rem); }
.counter-grid { display: grid; grid-template-columns: 1fr; gap: 0.75rem; }
.counter-item { background: var(--surface2); border-radius: var(--r); padding: 1rem; text-align: center; transition: background 0.3s; }
.counter-num { font-size: clamp(1.4rem, 4vw, 1.7rem); font-weight: 800; color: var(--accent); display: block; transition: color 0.3s; }
.counter-label { font-size: 0.75rem; font-weight: 600; color: var(--subtle); margin-top: 0.2rem; text-transform: uppercase; transition: color 0.3s; }

/* REDES SOCIALES */
.social-widget .widget-body { padding: clamp(1rem, 3vw, 1.5rem); }
.social-btns { display: grid; grid-template-columns: 1fr 1fr; gap: 0.75rem; width: 100%; }
.social-btn { display: flex; align-items: center; justify-content: center; gap: 0.5rem; padding: 0.75rem 0.5rem; border-radius: var(--r); font-size: 0.8rem; font-weight: 600; text-decoration: none; transition: opacity .2s, transform .2s; color: #fff; }
.social-btn:hover { opacity: 0.9; transform: translateY(-2px); }
.social-btn-fb { background: #1877F2; }
.social-btn-tg { background: #229ED9; }
.social-btn svg { width: 18px; height: 18px; fill: currentColor; flex-shrink: 0; }

/* NEWSLETTER */
.newsletter-widget { background: #0f172a !important; border: 1px solid var(--border) !important; }
.newsletter-widget .widget-head { border-bottom-color: rgba(255,255,255,0.1); color: rgba(255,255,255,0.5); }
.newsletter-body { padding: clamp(1rem, 3vw, 1.5rem); }
.newsletter-widget .newsletter-body h3 { font-size: 1.15rem; font-weight: 800; color: #fff; margin-bottom: 0.6rem; line-height: 1.3; }
.newsletter-widget .newsletter-body p { font-size: 0.85rem; color: rgba(255,255,255,0.7); margin-bottom: 1.25rem; }
.newsletter-form { display: flex; flex-direction: column; gap: 0.75rem; }
.newsletter-form input { width: 100%; background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.15); border-radius: var(--r); padding: 0.75rem 1rem; font-size: 0.9rem; color: #fff; outline: none; }
.btn-nl { width: 100%; background: var(--btn-primary); color: #0f172a; border: none; border-radius: var(--r); padding: 0.85rem; font-size: 0.9rem; font-weight: 700; cursor: pointer; }
.nl-privacy { font-size: 0.75rem; color: rgba(255,255,255,0.4); text-align: center; margin-top: 0.75rem; }

/* FOOTER */
footer { background: #0f172a; color: rgba(255,255,255,0.6); margin-top: 2rem; padding: clamp(2rem, 5vw, 3rem) clamp(1rem, 3vw, 1.5rem) 2rem; border-top: 1px solid var(--border); }
.footer-inner { max-width: var(--max); margin: 0 auto; }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: clamp(2rem, 5vw, 3rem); margin-bottom: 2.5rem; }
.footer-brand .logo { color: #fff; margin-bottom: 1rem; display: flex; align-items: center; }
.footer-brand p { font-size: 0.9rem; color: rgba(255,255,255,0.5); line-height: 1.65; max-width: 320px; margin-top: 0.5rem; }
.footer-col h4 { font-size: 0.85rem; font-weight: 700; text-transform: uppercase; color: rgba(255,255,255,0.6); margin-bottom: 1.25rem; }
.footer-col ul { list-style: none; display: flex; flex-direction: column; gap: 0.75rem; }
.footer-col a { font-size: 0.9rem; color: rgba(255,255,255,0.5); transition: color .2s; }
.footer-col a:hover { color: var(--btn-primary); }
.footer-bottom { border-top: 1px solid rgba(255,255,255,0.08); padding-top: 1.5rem; display: flex; justify-content: space-between; align-items: center; font-size: 0.85rem; flex-wrap: wrap; gap: 1rem; }

.loader-msg { padding: 40px; text-align: center; color: var(--subtle); font-weight: 600; }

@media (max-width: 1024px) {
  .page { grid-template-columns: 1fr; } 
  .sidebar { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); position: static; }
}

@media (max-width: 768px) {
  .hero-slider { height: auto; min-height: 400px; }
  .slide-bg { filter: none; opacity: 1; inset: 0; }
  .slide-overlay { background: linear-gradient(to top, rgba(15, 23, 42, 1) 0%, rgba(15, 23, 42, 0.6) 60%, transparent 100%); }
  .slide-content { display: flex; flex-direction: column; justify-content: flex-end; height: 100%; padding: 4rem 1.5rem 3.5rem 1.5rem; }
  .slide-text { text-align: left; width: 100%; }
  .slide-text p { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
  .slide-img-container { display: none; } 
}

@media (max-width: 680px) {
  .header-top { flex-direction: column; height: auto; gap: 1rem; justify-content: center; }
  .logo { width: 100%; justify-content: center; }
  .header-search { display: none; }
  .header-actions { width: 100%; justify-content: center; }
  .footer-bottom { flex-direction: column; text-align: center; }
  .reader-content pre { font-size: 0.75rem; padding: 10px !important; }
  .reader-content table { font-size: 0.8rem; }
  .reader-content th, .reader-content td { padding: 0.4rem 0.6rem; }
}

body.script:
//
(function() {
  const currentTheme = localStorage.getItem('mlh_theme');
  if (currentTheme === 'dark' || (!currentTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
    document.body.classList.add('dark-mode');
  }
})();
//

//
  document.addEventListener('DOMContentLoaded', () => {
    const feedContainer = document.getElementById('dynamic-feed');
    const readerContainer = document.getElementById('post-reader');
    const isSinglePost = window.location.pathname.includes('.html');
    const isHome = document.getElementById('hero-slider') !== null;

    const TARGET_CATEGORIES = ['Herramientas', 'Programas', 'Sistemas Operativos', 'Juegos', 'Personalización', 'Tips'];
    let ALL_POSTS = [];
    let TOTAL_POSTS_COUNT = 0;

    // --- MANEJADOR DE CAMBIO DE TEMA ---
    const themeToggleBtn = document.getElementById('theme-toggle');
    const darkIcon = themeToggleBtn.querySelector('.theme-icon-dark');
    const lightIcon = themeToggleBtn.querySelector('.theme-icon-light');

    function updateThemeIcons() {
      if (document.body.classList.contains('dark-mode')) {
        darkIcon.style.display = 'none';
        lightIcon.style.display = 'block';
      } else {
        darkIcon.style.display = 'block';
        lightIcon.style.display = 'none';
      }
    }

    updateThemeIcons();

    themeToggleBtn.addEventListener('click', () => {
      document.body.classList.toggle('dark-mode');
      const isDark = document.body.classList.contains('dark-mode');
      localStorage.setItem('mlh_theme', isDark ? 'dark' : 'light');
      updateThemeIcons();
    });

    // --- AGREGAR BOTONES DE COPIAR COMANDO ---
    function injectCopyButtons() {
      const preElements = document.querySelectorAll('.reader-content pre');
      preElements.forEach((pre) => {
        // Evitar inyecciones repetidas por re-renderizados fortuitos
        if (pre.parentElement.classList.contains('code-block-wrapper')) return;

        const wrapper = document.createElement('div');
        wrapper.className = 'code-block-wrapper';

        pre.parentNode.insertBefore(wrapper, pre);
        wrapper.appendChild(pre);

        const copyBtn = document.createElement('button');
        copyBtn.className = 'btn-copy-code';
        copyBtn.type = 'button';
        copyBtn.innerHTML = `
          <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
          <span>Copiar</span>
        `;

        copyBtn.addEventListener('click', async () => {
          const commandText = pre.textContent;
          try {
            await navigator.clipboard.writeText(commandText);
            copyBtn.classList.add('copied');
            copyBtn.querySelector('span').innerText = '¡Copiado!';
            setTimeout(() => {
              copyBtn.classList.remove('copied');
              copyBtn.querySelector('span').innerText = 'Copiar';
            }, 2000);
          } catch (err) {
            console.error('Error al intentar copiar el comando: ', err);
          }
        });

        wrapper.appendChild(copyBtn);
      });
    }

    async function fetchPosts() {
      try {
        const res = await fetch('/feeds/posts/default?alt=json&max-results=50');
        const data = await res.json();
        const entries = data.feed.entry || [];

        TOTAL_POSTS_COUNT = data.feed.openSearch$totalResults.$t;

        ALL_POSTS = entries.map(entry => {
          const title = entry.title.$t;
          const content = entry.content ? entry.content.$t : "";
          const categories = entry.category ? entry.category.map(c => c.term) : ['General'];
          const date = new Date(entry.published.$t).toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' });

          let link = "";
          entry.link.forEach(l => { if (l.rel === "alternate") link = l.href; });

          let thumb = "https://images.unsplash.com/photo-1629654297299-c8506221ca97?w=1200";
          if (entry.media$thumbnail) {
            thumb = entry.media$thumbnail.url.replace(/\/s[0-9]+(-[a-z])?\//, '/s1200/');
          } else {
            const imgMatch = content.match(/<img[^>]+src=["']([^"']+)["']/);
            if (imgMatch) thumb = imgMatch[1];
          }

          const textOnly = content.replace(/<[^>]+>/g, '').trim();
          const summary = textOnly.length > 150 ? textOnly.substring(0, 150) + '...' : textOnly;

          return { title, content, summary, thumb, link, categories, date };
        });

        renderSlider();
        renderView();
        initRealCounters();
      } catch (error) {
        if(feedContainer) feedContainer.innerHTML = '<p class="loader-msg">[ERROR] No se pudo conectar con el servidor.</p>';
      }
    }

    function renderSlider() {
      if (!isHome) return;
      const sliderTrack = document.getElementById('slider-track');
      const sliderDots = document.getElementById('slider-dots');

      const topPosts = ALL_POSTS.slice(0, 5);
      if (topPosts.length === 0) return;

      let slidesHTML = '';
      let dotsHTML = '';

      topPosts.forEach((post, i) => {
        const activeClass = i === 0 ? 'active' : '';
        const tag = post.categories.length > 0 ? post.categories[0] : 'Destacado';

        slidesHTML += `
          <div class="slide ${activeClass}" data-index="${i}">
            <div class="slide-bg" style="background-image: url('${post.thumb}')"></div>
            <div class="slide-overlay"></div>
            <div class="slide-content">
              <div class="slide-text">
                <span style="display:inline-block; font-size:0.75rem; font-weight:700; background:var(--btn-primary); color:#000; padding:0.3rem 0.8rem; border-radius:4px; margin-bottom:1rem; text-transform:uppercase;">${tag}</span>
                <h2>${post.title}</h2>
                <p>${post.summary}</p>
                <a href="${post.link}" class="btn-hero-primary">Leer artículo →</a>
              </div>
              <div class="slide-img-container">
                <img src="${post.thumb}" alt="${post.title}" loading="lazy"/>
              </div>
            </div>
          </div>
        `;
        dotsHTML += `<div class="dot ${activeClass}" data-index="${i}"></div>`;
      });

      sliderTrack.innerHTML = slidesHTML;
      sliderDots.innerHTML = dotsHTML;

      const slides = document.querySelectorAll('.slide');
      const dots = document.querySelectorAll('.dot');
      let currentSlide = 0;
      let slideInterval = setInterval(nextSlide, 10000);

      function goToSlide(index) {
        slides[currentSlide].classList.remove('active');
        dots[currentSlide].classList.remove('active');
        currentSlide = index;
        slides[currentSlide].classList.add('active');
        dots[currentSlide].classList.add('active');
      }

      function nextSlide() {
        let next = (currentSlide + 1) % slides.length;
        goToSlide(next);
      }

      dots.forEach(dot => {
        dot.addEventListener('click', (e) => {
          clearInterval(slideInterval);
          goToSlide(parseInt(e.target.dataset.index));
          slideInterval = setInterval(nextSlide, 10000); 
        });
      });
    }

    function renderView() {
      if (isSinglePost) {
        const matched = ALL_POSTS.find(p => new URL(p.link).pathname === window.location.pathname);
        const mainNav = document.getElementById('main-nav');
        if(mainNav) mainNav.style.display = 'none';
        if (feedContainer) feedContainer.style.display = 'none';

        if (matched && readerContainer) {
          readerContainer.style.display = 'block';
          readerContainer.innerHTML = `
            <h1 class="reader-title">${matched.title}</h1>
            <div class="reader-meta">
              <span>📅 Publicado: ${matched.date}</span>
              <span>📁 Categoría: ${matched.categories[0]}</span>
            </div>
            <div class="reader-content">${matched.content}</div>
            <div style="margin-top: 50px; padding-top: 30px; border-top: 1px solid var(--border); text-align: center;">
              <a href="/" class="btn-hero-primary" style="display:inline-block; font-size: clamp(0.9rem, 2vw, 1.1rem); padding: 1rem 2rem;">&larr; Volver a la Portada</a>
            </div>
          `;
          // EJECUTAR INYECCIÓN AUTOMÁTICA DE BOTONES PARA COPIAR COMANDOS Linux
          injectCopyButtons();
        } else {
          window.location.reload(); 
        }
      } else {
        if(readerContainer) readerContainer.style.display = 'none';
        if(feedContainer) feedContainer.innerHTML = '';

        const catCounts = {};
        ALL_POSTS.forEach(post => {
          post.categories.forEach(cat => {
            if (TARGET_CATEGORIES.includes(cat)) {
              catCounts[cat] = (catCounts[cat] || 0) + 1;
            }
          });
        });

        const topCategories = TARGET_CATEGORIES
          .filter(cat => catCounts[cat] > 0)
          .sort((a, b) => catCounts[b] - catCounts[a])
          .slice(0, 3);

        topCategories.forEach(cat => {
          const catPosts = ALL_POSTS.filter(p => p.categories.includes(cat)).slice(0, 3);
          if (catPosts.length > 0) {
            const section = document.createElement('section');
            section.className = 'category-block';

            const headerHTML = `
              <div class="section-header">
                <div class="section-title"><div class="section-icon">📁</div> ${cat}</div>
                <a href="/search/label/${cat}" class="section-all">Ver todos &rarr;</a>
              </div>
            `;

            let postsHTML = '<div class="posts-row">';
            catPosts.forEach(post => {
              postsHTML += `
                <article class="post-card" onclick="window.location.href='${post.link}'">
                  <img src="${post.thumb}" class="post-thumb" alt="${post.title}" loading="lazy"/>
                  <div class="post-body">
                    <span class="post-tag">${cat}</span>
                    <h3>${post.title}</h3>
                    <p>${post.summary}</p>
                    <div class="post-meta">
                      <span>📅 ${post.date}</span>
                      <span style="margin-left:auto; color:var(--accent); font-weight:700;">Leer &rarr;</span>
                    </div>
                  </div>
                </article>
              `;
            });
            postsHTML += '</div>';

            section.innerHTML = headerHTML + postsHTML;
            feedContainer.appendChild(section);
          }
        });

        if(feedContainer.innerHTML === '') {
           feedContainer.innerHTML = '<p class="loader-msg">Aún no hay artículos publicados con estas etiquetas.</p>';
        }
      }
    }

    function initRealCounters() {
      const vEl = document.getElementById('cnt-visitas');
      const pEl = document.getElementById('cnt-posts');

      if (vEl) {
         const realStatsEl = document.getElementById('real-blogger-stats');
         let visitsToShow = 148392;

         if (realStatsEl && realStatsEl.innerText.trim() !== '' && !isNaN(realStatsEl.innerText.replace(/,/g, ''))) {
             visitsToShow = parseInt(realStatsEl.innerText.replace(/,/g, ''));
         } else {
             visitsToShow = parseInt(localStorage.getItem('mlh_visitas_totales') || 148392);
             visitsToShow = visitsToShow + Math.floor(Math.random() * 4) + 1;
             localStorage.setItem('mlh_visitas_totales', visitsToShow);
         }
         vEl.innerText = String(visitsToShow).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
      }

      if (pEl) {
         pEl.innerText = TOTAL_POSTS_COUNT || "0";
      }
    }

    fetchPosts();
  });
//
